mapper.select:
select *
from hd_post
where
    title like concat('%',#{search},'%') and status = '1' and username = #{username}
   or
    `describe` like concat('%',#{search},'%') and status = '1' and username = #{username}
   or
    username like concat('%',#{search},'%') and status = '1' and username = #{username}
